#include <stdio.h>
#include <stdlib.h>
#define MAX_N 35
#define MAX_M 35
#define MAX_Q 105

int grid[MAX_N][MAX_M];
int P1[6], P2[6];

int main() {
    int N, M, Q;
    scanf("%d %d %d", &N, &M, &Q);
    int Sx, Sy;
    scanf("%d %d", &Sx, &Sy);
    for (int i = 0; i < 6; i++) {
        scanf("%d %d", &P1[i], &P2[i]);
    }
    while (Q--) {
        long long T;
        scanf("%lld", &T);
        long long sum = 0;
        for (int t = 0; t <= T; t++) {
            sum += simulate(N, M, t, Sx, Sy, P1, P2);
        }
        printf("%lld\n", sum);
    }
    return 0;
}

int simulate(int N, int M, int t, int Sx, int Sy, int P1[], int P2[]) {
    // Initialize the grid
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            grid[i][j] = 0;
        }
    }
    grid[Sx - 1][Sy - 1] = 1;
    for (int i = 0; i < t; i++) {
        // Update the grid according to the rules
        for (int x = 0; x < N; x++) {
            for (int y = 0; y < M; y++) {
                if (grid[x][y] > 0) {
                    int F = 0;
                    for (int j = 0; j < M; j++) {
                        F += grid[x][j];
                    }
                    for (int j = 0; j < N; j++) {
                        F += grid[j][y];
                    }
                    F -= grid[x][y];
                    int X = F % 6;
                    int D1 = (X == 0 || X == 2) ? -1 : (X == 1 || X == 5) ? -1 : 1;
                    int D2 = (X == 0) ? 1 : (X == 1 || X == 4) ? 1 : -1;
                    int P1_val = P1[X], P2_val = P2[X];
                    for (int j = 1; j <= N; j++) {
                        int nx = x + j * D1;
                        int ny = y;
                        if (nx >= 0 && nx < N && ny >= 0 && ny < M && j % P1_val == 0) {
                            grid[nx][ny] += grid[x][y];
                        }
                    }
                    for (int j = 1; j <= M; j++) {
                        int nx = x;
                        int ny = y + j * D2;
                        if (nx >= 0 && nx < N && ny >= 0 && ny < M && j % P2_val == 0) {
                            grid[nx][ny] += grid[x][y];
                        }
                    }
                }
            }
        }
        // Update the number of images at each cell
        for (int x = 0; x < N; x++) {
            for (int y = 0; y < M; y++) {
                grid[x][y] %= 2;
            }
        }
    }
    // Count the number of images on the grid
    int count = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            count += grid[i][j];
        }
    }
    return count;
}

