P2 = [0]*6

def simulate(N, M, t, Sx, Sy):
    # Initialize the grid
    for i in range(N):
        for j in range(M):
            grid[i][j] = 0
    grid[Sx-1][Sy-1] = 1
    for _ in range(t):
        # Update the grid according to the rules
        for x in range(N):
            for y in range(M):
                if grid[x][y] > 0:
                    F = 0
                    for j in range(M):
                        F += grid[x][j]
                    for j in range(N):
                        F += grid[j][y]
                    F -= grid[x][y]
                    X = F % 6
                    D1 = -1 if X in [0, 2] else 1 if X in [3] else -1
                    D2 = 1 if X in [0] else 1 if X in [1, 4] else -1
                    P1_val = P1[X]
                    P2_val = P2[X]
                    for j in range(1, N+1):
                        nx = x + j * D1
                        ny = y
                        if 0 <= nx < N and 0 <= ny < M and j % P1_val == 0:
                            grid[nx][ny] += grid[x][y]
                    for j in range(1, M+1):
                        nx = x
                        ny = y + j * D2
                        if 0 <= nx < N and 0 <= ny < M and j % P2_val == 0:
                            grid[nx][ny] += grid[x][y]
        # Update the number of images at each cell
        for x in range(N):
            for y in range(M):
                grid[x][y] %= 2
    # Count the number of images on the grid
    count = 0
    for i in range(N):
        for j in range(M):
            count += grid[i][j]
    return count

